const fieldData = $json.field_data || [];
const fields = {};
for (const field of fieldData) {
  fields[field.name] = field.values ? field.values[0] : '';
}
return {
  nombre: fields.full_name || fields.nombre || fields.name || '',
  email: fields.email || '',
  telefono: fields.phone_number || fields.telefono || fields.phone || '',
  empresa: fields.company_name || fields.empresa || fields.company || '',
  meta_lead_id: $json.id,
  created_time: $json.created_time
};
